# Simple regex parser
matches = re.findall(r'<h1[^>]*>.*?<span[^>]*>(.*?)</span>.*?<a[^>]*href=["\']([^"\']+)["\']', raw_html, re.DOTALL | re.IGNORECASE)

unique_videos = {}
for raw_title, raw_link in matches:
    # Decode html entities
    title = html.unescape(raw_title).strip()
    title = re.sub(r'<[^>]+>', '', title)  # remove inline tags if any
    
    # Extract redirect url if google redirect
    link = raw_link
    if "google.com/url?q=" in raw_link:
        parsed_q = re.search(r'q=([^&]+)', raw_link)
        if parsed_q:
            import urllib.parse
            link = urllib.parse.unquote(parsed_q.group(1))
            
    # Clean si parameter
    link = re.sub(r'\?si=[^&]+', '', link)
    link = re.sub(r'\&si=[^&]+', '', link)
    
    # Unique check by title and link
    key = (title, link)
    if key not in unique_videos:
        unique_videos[key] = {
            "title": title,
            "link": link
        }

print(f"Extracted {len(unique_videos)} unique videos from partial html")
print(json.dumps(list(unique_videos.values())[:3], ensure_ascii=False, indent=2))
